module adder_32bit(
    input [32:1] A,
    input [32:1] B,
    output [32:1] S,
    output C32
);

wire [15:0] P1, G1, P2, G2;
wire C1, C2;

genvar i;
    for (i = 0; i < 16; i = i + 1) begin : gen_prop_signals
        end // Auto-repaired
        assign P1[i] = A[i+1] ^ B[i+1];
        assign G1[i] = A[i+1] & B[i+1];
    end

wire [15:0] S1;
wire C1_out;
wire C1_in = 1'b0;
wire [1:0] cla1_carry;
assign cla1_carry[0] = C1_in;
assign C1 = cla1_carry[1];

    for (i = 0; i < 16; i = i + 1) begin : gen_prop_signals2
        assign P2[i] = A[i+17] ^ B[i+17];
        assign G2[i] = A[i+17] & B[i+17];
    end

wire [15:0] S2;
wire C2_out;
assign C2_in = C1;
assign cla2_carry[0] = C2_in;
assign C32 = cla2_carry[1];

assign S[16:1] = S1;
assign S[32:17] = S2;

endmodule
